import{_ as e,a,b as n,c as i}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as c,o as d,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Thêm S3 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/s3.md","filePath":"vi-VN/upload/s3.md","lastUpdated":1781962217000}'),l={name:"vi-VN/upload/s3.md"};function h(r,t,p,u,g,m){return d(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="them-s3-channel" tabindex="-1">Thêm S3 Channel <a class="header-anchor" href="#them-s3-channel" aria-label="Permalink to &quot;Thêm S3 Channel&quot;">​</a></h1><h2 id="phu-hop-nhat-khi-nao" tabindex="-1">Phù hợp nhất khi nào <a class="header-anchor" href="#phu-hop-nhat-khi-nao" aria-label="Permalink to &quot;Phù hợp nhất khi nào&quot;">​</a></h2><p>Dùng S3 channel khi:</p><ul><li>Bạn muốn kết nối object storage service tương thích S3, như Cloudflare R2, Backblaze B2, MinIO, AWS S3 hoặc provider tương thích khác.</li><li>Bạn thích mô hình cấu hình S3 chuẩn: <code>Endpoint</code>, Access Key và Secret Key.</li><li>Bạn không muốn dùng native Cloudflare R2 binding channel, hoặc storage provider của bạn không phải Cloudflare R2.</li></ul><h2 id="can-chuan-bi-gi-truoc-khi-bat-đau" tabindex="-1">Cần chuẩn bị gì trước khi bắt đầu <a class="header-anchor" href="#can-chuan-bi-gi-truoc-khi-bat-đau" aria-label="Permalink to &quot;Cần chuẩn bị gì trước khi bắt đầu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>S3 API endpoint của object storage service.</td></tr><tr><td>Bucket name</td><td>Bucket dùng để lưu files.</td></tr><tr><td>Region</td><td>Storage region. Với Cloudflare R2 thường là <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>Custom domain tùy chọn cho file access.</td></tr></tbody></table><p>Ví dụ Cloudflare R2 qua S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="them-o-đau" tabindex="-1">Thêm ở đâu <a class="header-anchor" href="#them-o-đau" aria-label="Permalink to &quot;Thêm ở đâu&quot;">​</a></h2><ol><li>Mở System Settings.</li><li>Vào Upload Settings.</li><li>Nhấn Add Channel ở góc trên bên phải.</li><li>Chọn <code>S3</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Tác dụng</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết cho S3 channel, ví dụ <code>s3test</code> hoặc <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>Kiểm soát channel này có tham gia upload selection hay không.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>Full S3 service endpoint, bao gồm <code>https://</code>.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional. Khi đặt, generated file links sẽ ưu tiên domain này.</td><td>No</td></tr><tr><td>Bucket name</td><td>Bucket name, ví dụ <code>s3test</code> hoặc <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. Với Cloudflare R2 thường là <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>Compatibility switch. Mặc định off. Một số MinIO, OpenList hoặc self-hosted S3 service có thể cần.</td><td>No</td></tr><tr><td>Quota limit</td><td>Kiểm soát S3 channel này có tham gia upload selection theo capacity hay không.</td><td>No</td></tr><tr><td>Capacity limit</td><td>Required sau khi bật quota limit, ví dụ <code>10 GB</code>.</td><td>Required khi bật quota limit</td></tr><tr><td>Threshold</td><td>Dừng ghi khi usage đạt percentage này, ví dụ <code>90%</code>.</td><td>Required khi bật quota limit</td></tr><tr><td>Remark</td><td>Ghi chú để tự bảo trì.</td><td>No</td></tr></tbody></table><h2 id="tao-cloudflare-r2-s3-api-keys" tabindex="-1">Tạo Cloudflare R2 S3 API Keys <a class="header-anchor" href="#tao-cloudflare-r2-s3-api-keys" aria-label="Permalink to &quot;Tạo Cloudflare R2 S3 API Keys&quot;">​</a></h2><ol><li>Mở Cloudflare Dashboard.</li><li>Vào <code>R2 Object Storage</code>.</li><li>Tìm <code>Manage R2 API Tokens</code> hoặc mục quản lý API token.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Tạo R2 API token có quyền access target bucket.</li></ol><p><img src="`+e+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>Copy <code>Access Key ID</code> và <code>Secret Access Key</code> được tạo.</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>Quay lại trang R2 bucket và xác nhận bucket name.</li><li>Ghi lại S3 API endpoint của account. Thường có dạng:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><ol><li>Mở Upload Settings.</li><li>Nhấn Add Channel.</li><li>Chọn <code>S3</code>.</li><li>Nhập channel name dễ nhận biết, ví dụ <code>s3test</code>.</li><li>Nhập S3 API endpoint trong <code>Endpoint</code>.</li><li>Nếu dùng custom CDN, nhập trong <code>Custom CDN domain</code>; nếu không thì để trống.</li><li>Nhập bucket name.</li><li>Nhập region. Với ví dụ Cloudflare R2, dùng <code>auto</code>.</li><li>Nhập Access Key ID và Secret Access Key.</li><li>Giữ path-style access ở off trừ khi provider yêu cầu rõ.</li><li>Nếu muốn capacity control, bật quota limit rồi nhập capacity limit và threshold.</li><li>Nhấn Save.</li></ol><p><img src="'+n+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="cach-kiem-tra" tabindex="-1">Cách kiểm tra <a class="header-anchor" href="#cach-kiem-tra" aria-label="Permalink to &quot;Cách kiểm tra&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cách kiểm tra</th></tr></thead><tbody><tr><td>Channel card xuất hiện</td><td>Sau khi save, trang Upload Settings cần hiển thị S3 channel card.</td></tr><tr><td>Channel enabled</td><td>Switch ở góc trên bên phải card nên ở trạng thái on.</td></tr><tr><td>Key fields đã lưu</td><td>Detail view cần hiển thị Endpoint, Bucket, Region, path-style access và các field liên quan.</td></tr><tr><td>Upload hoạt động</td><td>Upload test image và xác nhận object xuất hiện trong target bucket.</td></tr><tr><td>Link mở được</td><td>Image link trả về sau upload cần mở bình thường.</td></tr><tr><td>Capacity display hoạt động</td><td>Nếu bật quota limit, card cần hiển thị used capacity và configured limit.</td></tr></tbody></table><p>S3 capacity statistics được tính từ local file records của ImgBed, không query provider bucket theo real time. Sau khi save S3 configuration, system sẽ recalculate quota ledger từ current D1 records.</p><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="co-nen-bat-path-style-access-khong" tabindex="-1">Có nên bật path-style access không? <a class="header-anchor" href="#co-nen-bat-path-style-access-khong" aria-label="Permalink to &quot;Có nên bật path-style access không?&quot;">​</a></h3><p>Thường là không.</p><p>Chỉ bật khi S3-compatible provider không hỗ trợ virtual-hosted-style URLs, hoặc provider documentation yêu cầu path-style access rõ ràng. Một số MinIO, self-hosted S3 và OpenList-compatible endpoints có thể cần.</p><h3 id="cdn-domain-dung-đe-lam-gi" tabindex="-1">CDN domain dùng để làm gì? <a class="header-anchor" href="#cdn-domain-dung-đe-lam-gi" aria-label="Permalink to &quot;CDN domain dùng để làm gì?&quot;">​</a></h3><p>Nếu bạn đặt CDN hoặc custom access domain trước bucket, nhập domain đó ở đây.</p><p>Sau khi cấu hình, generated file links sẽ ưu tiên domain này. Nếu không dùng CDN, để trống.</p><h3 id="vi-sao-upload-fail" tabindex="-1">Vì sao upload fail? <a class="header-anchor" href="#vi-sao-upload-fail" aria-label="Permalink to &quot;Vì sao upload fail?&quot;">​</a></h3><p>Kiểm tra các mục này trước:</p><ol><li>Endpoint là full <code>https://</code> URL.</li><li>Bucket name chính xác.</li><li>Region khớp với yêu cầu của provider.</li><li>Access Key ID và Secret Access Key được copy đầy đủ.</li><li>Key có write permission cho target bucket.</li><li>Provider không yêu cầu path-style access, hoặc đã bật path-style access nếu cần.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chuẩn bị S3 Endpoint, Bucket, Region, Access Key và Secret Key</span></span>
<span class="line"><span>-&gt; Mở Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Chọn S3</span></span>
<span class="line"><span>-&gt; Nhập Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Nhập CDN domain nếu cần</span></span>
<span class="line"><span>-&gt; Giữ path-style access off theo mặc định</span></span>
<span class="line"><span>-&gt; Bật quota limit nếu cần</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Upload test image và kiểm tra kết quả</span></span></code></pre></div>`,40)])])}const f=c(l,[["render",h]]);export{y as __pageData,f as default};
